import O9Button from '../Button/Button';
import type { HybridPopoverEmptyConfig } from './HybridPopover';

export interface EmptyStateProps {
  kind: 'no-data' | 'no-results';
  config?: HybridPopoverEmptyConfig;
  onClear?: () => void;
}

const DEFAULTS: Required<HybridPopoverEmptyConfig> = {
  noDataTitle: 'No data available',
  noDataMessage: 'Adjust your filter search query.',
  noResultsTitle: 'No results found',
  noResultsMessage: 'Adjust your filter search query.',
  noResultsClearLabel: 'Clear Search',
};

export function EmptyState({ kind, config = {}, onClear }: EmptyStateProps) {
  const cfg = { ...DEFAULTS, ...config };
  const isNoResults = kind === 'no-results';

  const title = isNoResults ? cfg.noResultsTitle : cfg.noDataTitle;
  const message = isNoResults ? cfg.noResultsMessage : cfg.noDataMessage;
  const illusClass = isNoResults
    ? 'o9illus o9illus-no-results-found'
    : 'o9illus o9illus-no-filters-found';

  const classes = [
    'o9ds-hpop__empty',
    isNoResults ? 'o9ds-hpop__empty--no-results' : 'o9ds-hpop__empty--no-data',
  ].join(' ');

  return (
    <div className={classes} role="status">
      <span className={`o9ds-hpop__empty-illus ${illusClass}`} aria-hidden="true" />
      <span className="o9ds-hpop__empty-title">{title}</span>
      <span className="o9ds-hpop__empty-msg">{message}</span>
      {isNoResults && onClear && (
        <span className="o9ds-hpop__empty-action">
          <O9Button
            label={cfg.noResultsClearLabel}
            variant="outline"
            size="sm"
            onClick={onClear}
          />
        </span>
      )}
    </div>
  );
}

export default EmptyState;
